    z = 0
    for i, ch in enumerate(s):
        z = ((z * 131) ^ (ord(ch) + (i << 1) + 7)) & 0xffffffff

    def warp(buf, seed):
        k = seed.to_bytes(4, "little")
        out = bytearray(32)
        for i in range(32):
            b = buf[31 - i]
            out[i] = ((b ^ k[i & 3]) + (i * 17 + 19)) & 255
        return bytes(out)

    a = sha256(s.encode()).digest()
    b = sha256((0).to_bytes(0, "big")).digest()
    return warp(a, z) == warp(b, z)
